import React, { useState, useEffect } from 'react';
import Graph from './Graph';
import { pointAPI, authAPI } from './api';

function MainPage({ onLogout }) {
  const [x, setX] = useState('');
  const [y, setY] = useState('');
  const [r, setR] = useState('');
  const [results, setResults] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [username, setUsername] = useState('');

  const xOptions = [-3, -2, -1, 0, 1, 2, 3, 4, 5];
  const rOptions = [1, 2, 3, 4, 5];


  // Загружаем результаты при загрузке
  useEffect(() => {
      loadResults();
      const savedUsername = localStorage.getItem('username');
      if (savedUsername) {
        setUsername(savedUsername);
      }
    }, []);

  const loadResults = async () => {
    const result = await pointAPI.getResults();
    if (result.success) {
      setResults(result.data);
    }
  };

  const handleSubmit = async (e) => {
      e.preventDefault();
      setError('');

      if (!x || y === '' || !r) {
        setError('Заполните все поля');
        return;
      }

      const xNum = parseFloat(x);
      const yNum = parseFloat(y);
      const rNum = parseFloat(r);

      if (isNaN(yNum)) {
        setError('Y должен быть числом');
        return;
      }

      if (yNum < -5 || yNum > 3) {
        setError('Y должен быть в диапазоне от -5 до 3');
        return;
      }

      setLoading(true);
      const result = await pointAPI.checkPoint(xNum, yNum, rNum);
      setLoading(false);

      if (result.success) {
        setResults(prev => [result.data, ...prev]);
        setY('');
      } else {
        setError(result.message);
      }
    };

  const handleClearResults = async () => {
    if (window.confirm('Вы уверены, что хотите очистить историю?')) {
      const result = await pointAPI.clearResults();
      if (result.success) {
        setResults([]);
      }
    }
  };

  const handleLogout = async () => {
    await authAPI.logout();
    onLogout();
  };

  const handleCanvasClick = async (clickX, clickY) => {
    const result = await pointAPI.checkPoint(clickX, clickY, r);
    if (result.success) {
      setResults(prev => [result.data, ...prev]);
    }
  };

  return (
      <div className="main-container">
        <header className="header">
          <div>
            <h1>Проверка попадания точки в область</h1>
            <p>Пользователь: {username}</p>
          </div>
          <button onClick={handleLogout} className="logout-btn">
            Выйти
          </button>
        </header>

        <div className="content">
          <div className="form-section">
            <form onSubmit={handleSubmit} className="point-form">
              <h2>Введите координаты</h2>

              {/* X: selectOneMenu */}
              <div className="form-group">
                <label>Координата X (select):</label>
                <select
                  value={x}
                  onChange={(e) => setX(e.target.value)}
                  className="form-select"
                >
                  <option value="">Выберите X</option>
                  {xOptions.map(value => (
                    <option key={value} value={value}>
                      {value}
                    </option>
                  ))}
                </select>
              </div>

              {/* Y: inputText */}
              <div className="form-group">
                <label htmlFor="y">Координата Y (input):</label>
                <input
                  type="number"
                  id="y"
                  value={y}
                  onChange={(e) => setY(e.target.value)}
                  placeholder="-5 ... 3"
                  min="-5"
                  max="3"
                  step="0.1"
                  className="form-input"
                />
                <small>Диапазон: от -5 до 3</small>
              </div>

              {/* R: selectBooleanCheckBox (radio buttons) */}
              <div className="form-group">
                <label>Радиус R (radio):</label>
                <div className="radio-group">
                  {rOptions.map(value => (
                    <label key={value} className="radio-label">
                      <input
                        type="radio"
                        name="r"
                        value={value}
                        checked={r === value.toString()}
                        onChange={(e) => setR(e.target.value)}
                      />
                      {value}
                    </label>
                  ))}
                </div>
              </div>

              {error && <div className="error-message">{error}</div>}

              <button
                type="submit"
                className="submit-btn"
                disabled={loading || !x || !r}
              >
                {loading ? 'Проверка...' : 'Проверить'}
              </button>
            </form>

            <div className="action-buttons">
              <button
                onClick={handleClearResults}
                className="clear-btn"
                disabled={results.length === 0}
              >
                Очистить историю
              </button>
            </div>
          </div>

          <div className="graph-section">
            <Graph
              results={results}
              currentR={r ? parseFloat(r) : null}
              onCanvasClick={handleCanvasClick}
            />

          <div className="results-section">
            <h2>История проверок</h2>
            {results.length === 0 ? (
              <p className="no-results">Нет результатов. Проверьте точку!</p>
            ) : (
              <table className="results-table">
                <thead>
                  <tr>
                    <th>X</th>
                    <th>Y</th>
                    <th>R</th>
                    <th>Результат</th>
                    <th>Время</th>
                  </tr>
                </thead>
                <tbody>
                  {results.map((result, index) => (
                    <tr
                      key={index}
                      className={result.hit ? 'hit-row' : 'miss-row'}
                    >
                      <td>{result.x.toFixed(3)}</td>
                      <td>{result.y.toFixed(3)}</td>
                      <td>{result.r}</td>
                      <td>
                        <span className={result.hit ? 'hit' : 'miss'}>
                          {result.hit ? 'Попадание' : 'Промах'}
                        </span>
                      </td>
                      <td>
                        {new Date(result.createdAt).toLocaleString('ru-RU')}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default MainPage;
